1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	type Step = QuoteStep;
13	
14	interface Scenario {
15	  customer: { yearsWithMHPCO: number };
16	  steps: Step[];
17	}
18	
19	interface QuoteResult {
20	  premium: number;
21	}
22	
23	interface ScenarioOutput {
24	  results: QuoteResult[];
25	}
26	
27	const PROCESSING_FEE = 5;
28	const COMPONENT_TYPES = ["rune", "moonstone"];
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const isComponent = (item: Item): boolean =>
42	  COMPONENT_TYPES.includes(item.type);
43	
44	const calculateComponentPremium = (
45	  componentCounts: Record<string, number>,
46	): number => {
47	  let total = 0;
48	  for (const [type, count] of Object.entries(componentCounts)) {
49	    total +=
50	      count === BLOCK_SIZE
51	        ? BLOCK_PREMIUM
52	        : count * (BASE_PREMIUMS[type] ?? 0);
53	  }
54	  return total;
55	};
56	
57	export function processScenario(scenario: Scenario): ScenarioOutput {
58	  const results = scenario.steps.map((step) => {
59	    const componentCounts: Record<string, number> = {};
60	    let totalBeforeFee = 0;
61	
62	    for (const item of step.items) {
63	      if (isComponent(item)) {
64	        componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
65	      } else {
66	        const itemBase = BASE_PREMIUMS[item.type] ?? 0;
67	        let itemPremium = itemBase;
68	        if (item.cursed) {
69	          itemPremium += itemBase * 0.5;
70	        }
71	        if ((item.enchantment ?? 0) >= 5) {
72	          itemPremium += itemBase * 0.3;
73	        }
74	        totalBeforeFee += itemPremium;
75	      }
76	    }
77	
78	    totalBeforeFee += calculateComponentPremium(componentCounts);
79	
80	    return { premium: totalBeforeFee + PROCESSING_FEE };
81	  });
82	  return { results };
83	}
